// Tattletales — screens.jsx
// All UI components for the prototype. Reads EPISODES & VIBES from window.

// ─────────────────────────────────────────────────────────────
// Atoms
// ─────────────────────────────────────────────────────────────
function TTTape({ children, color = '#ffe066', rot = -3, style = {} }) {
  return (
    <span style={{
      display: 'inline-block', padding: '4px 10px 5px',
      fontFamily: '"Space Grotesk", system-ui', fontWeight: 700,
      fontSize: 11, letterSpacing: '0.14em', textTransform: 'uppercase',
      color: '#15110b',
      background: color,
      transform: `rotate(${rot}deg)`,
      boxShadow: '1px 1px 0 rgba(0,0,0,0.12)',
      ...style,
    }}>{children}</span>
  );
}

function TTStamp({ children, color = '#c41e3a', rot = -8, size = 80, style = {} }) {
  return (
    <div style={{
      width: size, height: size, borderRadius: '50%',
      border: `2px solid ${color}`, color,
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      fontFamily: '"Space Grotesk", system-ui', fontWeight: 700,
      fontSize: size * 0.16, letterSpacing: '0.14em',
      textTransform: 'uppercase', textAlign: 'center',
      transform: `rotate(${rot}deg)`,
      opacity: 0.85, lineHeight: 1,
      ...style,
    }}>{children}</div>
  );
}

function TTPill({ children, dark = false, style = {} }) {
  return (
    <span style={{
      display: 'inline-flex', alignItems: 'center', gap: 6,
      padding: '5px 9px 5px 8px', borderRadius: 999,
      fontFamily: '"Space Grotesk", system-ui', fontWeight: 600,
      fontSize: 10.5, letterSpacing: '0.06em', textTransform: 'uppercase',
      background: dark ? 'rgba(255,255,255,0.12)' : 'rgba(0,0,0,0.06)',
      color: 'inherit',
      ...style,
    }}>{children}</span>
  );
}

// A tiny "LIVE" / "NEW" pulse dot
function TTDot({ color = '#ff2e63' }) {
  return (
    <span style={{ position: 'relative', display: 'inline-block', width: 7, height: 7 }}>
      <span style={{
        position: 'absolute', inset: 0, borderRadius: '50%', background: color,
        animation: 'tt-pulse 1.6s ease-out infinite',
      }} />
      <span style={{
        position: 'absolute', inset: 0, borderRadius: '50%', background: color,
      }} />
    </span>
  );
}

// ─────────────────────────────────────────────────────────────
// Poster — the central visual unit
// kind: 'hero' | 'card' | 'tile' | 'fullbleed'
// ─────────────────────────────────────────────────────────────
function Poster({ ep, kind = 'card', onClick, style = {} }) {
  const p = ep.palette;
  const dims = {
    hero:      { w: '100%', h: 380, titleSize: 64, padding: 22 },
    card:      { w: '100%', h: 260, titleSize: 44, padding: 16 },
    tile:      { w: 130,    h: 170, titleSize: 26, padding: 12 },
    fullbleed: { w: '100%', h: '100%', titleSize: 84, padding: 28 },
  }[kind];

  return (
    <div onClick={onClick} style={{
      position: 'relative', overflow: 'hidden',
      width: dims.w, height: dims.h, borderRadius: kind === 'fullbleed' ? 0 : 14,
      background: p.bg, color: p.ink,
      cursor: onClick ? 'pointer' : 'default',
      boxShadow: kind === 'fullbleed' ? 'none' : `0 1px 0 rgba(255,255,255,0.5) inset, 0 8px 30px rgba(0,0,0,0.15)`,
      flexShrink: 0,
      ...style,
    }}>
      {/* halftone-ish dot texture */}
      <div aria-hidden style={{
        position: 'absolute', inset: 0, opacity: 0.10, pointerEvents: 'none',
        backgroundImage: `radial-gradient(${p.ink} 0.7px, transparent 0.8px)`,
        backgroundSize: '6px 6px',
      }} />
      {/* tape */}
      <div style={{ position: 'absolute', top: 12, left: -10, zIndex: 2 }}>
        <TTTape color={p.tape}>{ep.kicker}</TTTape>
      </div>
      {/* ep number top right */}
      <div style={{
        position: 'absolute', top: dims.padding, right: dims.padding,
        fontFamily: '"Space Grotesk", system-ui', fontWeight: 600,
        fontSize: kind === 'tile' ? 9 : 11, letterSpacing: '0.16em',
        opacity: 0.7,
      }}>{ep.ep}</div>

      {/* title block — bottom anchored */}
      <div style={{
        position: 'absolute', left: dims.padding, right: dims.padding,
        bottom: dims.padding,
      }}>
        <div style={{
          fontFamily: '"Anton", "Oswald", "Impact", sans-serif',
          fontWeight: 400, fontSize: dims.titleSize,
          lineHeight: 0.88, letterSpacing: '-0.005em',
          textTransform: 'uppercase',
          textWrap: 'balance',
        }}>{ep.title}</div>
        {kind !== 'tile' && (
          <div style={{
            marginTop: 10,
            fontFamily: '"Instrument Serif", "Times New Roman", serif',
            fontStyle: 'italic', fontSize: kind === 'fullbleed' ? 22 : 15.5,
            lineHeight: 1.25, opacity: 0.85, textWrap: 'pretty',
          }}>"{ep.logline}"</div>
        )}
      </div>

      {/* corner stamp (not on tile) */}
      {kind !== 'tile' && (
        <div style={{ position: 'absolute', top: 28, right: 16, zIndex: 1 }}>
          <TTStamp color={p.accent} size={kind === 'hero' || kind === 'fullbleed' ? 78 : 62} rot={12}>
            {ep.stamp}
          </TTStamp>
        </div>
      )}

      {/* runtime chip bottom-left for hero/fullbleed */}
      {(kind === 'hero' || kind === 'fullbleed') && (
        <div style={{ position: 'absolute', top: dims.padding + 30, left: dims.padding }}>
          <TTPill style={{ background: 'rgba(0,0,0,0.08)', color: p.ink }}>
            <TTDot color={p.accent} /> {ep.mins} min · drama
          </TTPill>
        </div>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────
// Story ring — Instagram-style circle gateway
// ─────────────────────────────────────────────────────────────
function StoryRing({ ep, watched, onClick }) {
  const p = ep.palette;
  return (
    <button onClick={onClick} style={{
      all: 'unset', cursor: 'pointer', display: 'flex',
      flexDirection: 'column', alignItems: 'center', gap: 6,
      flexShrink: 0, width: 76,
    }}>
      <div style={{
        width: 72, height: 72, borderRadius: '50%', padding: 3,
        background: watched
          ? 'transparent'
          : `conic-gradient(from 220deg, ${p.accent}, ${p.tape}, ${p.accent})`,
        border: watched ? '1.5px dashed currentColor' : 'none',
        opacity: watched ? 0.5 : 1,
        boxSizing: 'border-box',
      }}>
        <div style={{
          width: '100%', height: '100%', borderRadius: '50%',
          background: p.bg, color: p.ink,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontFamily: '"Anton", sans-serif', fontSize: 28, lineHeight: 1,
          border: '2px solid var(--page,#f4ecde)',
          position: 'relative', overflow: 'hidden',
        }}>
          <span style={{ position: 'absolute', inset: 0,
            backgroundImage: `radial-gradient(${p.ink} 0.6px, transparent 0.7px)`,
            backgroundSize: '5px 5px', opacity: 0.10 }} />
          <span style={{ position: 'relative' }}>{ep.id}</span>
        </div>
      </div>
      <div style={{
        fontFamily: '"Space Grotesk", system-ui', fontWeight: 500,
        fontSize: 11, letterSpacing: '0.04em',
        opacity: watched ? 0.5 : 0.9, textAlign: 'center',
        whiteSpace: 'nowrap', maxWidth: 76, overflow: 'hidden', textOverflow: 'ellipsis',
      }}>{ep.kicker.toLowerCase()}</div>
    </button>
  );
}

// ─────────────────────────────────────────────────────────────
// Bottom tab bar
// ─────────────────────────────────────────────────────────────
function TabBar({ tab, setTab, vibe }) {
  const tabs = [
    { id: 'stories', label: 'Stories',
