// ─────────────────────────────────────────────────────────────
// STORY — instagram-style tap-through
// ─────────────────────────────────────────────────────────────
function StoryScreen({ episodeId, onClose, onOpenDetail, onAdvanceEpisode }) {
  const ep = window.EPISODES.find(e => e.id === episodeId);
  const cards = ep.cards;
  const [idx, setIdx] = React.useState(0);
  const [paused, setPaused] = React.useState(false);
  const DURATION = 4200;

  // Progress timer
  const [progress, setProgress] = React.useState(0);
  React.useEffect(() => {
    setProgress(0);
    if (paused) return;
    const start = performance.now();
    let raf;
    const tick = (t) => {
      const pct = Math.min(1, (t - start) / DURATION);
      setProgress(pct);
      if (pct < 1) raf = requestAnimationFrame(tick);
      else next();
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
    // eslint-disable-next-line
  }, [idx, paused, episodeId]);

  const next = () => {
    if (idx < cards.length - 1) setIdx(idx + 1);
    else onAdvanceEpisode();
  };
  const prev = () => {
    if (idx > 0) setIdx(idx - 1);
  };

  const card = cards[idx];
  const p = ep.palette;
  const isDark = ['#0d0709','#020a06'].includes(p.bg);

  return (
    <div style={{
      position: 'absolute', inset: 0, background: p.bg, color: p.ink,
      zIndex: 40, overflow: 'hidden',
    }}>
      {/* halftone */}
      <div aria-hidden style={{
        position: 'absolute', inset: 0, opacity: 0.10, pointerEvents: 'none',
        backgroundImage: `radial-gradient(${p.ink} 0.7px, transparent 0.8px)`,
        backgroundSize: '6px 6px',
      }} />

      {/* progress bars */}
      <div style={{
        position: 'absolute', top: 56, left: 12, right: 12, zIndex: 5,
        display: 'flex', gap: 4,
      }}>
        {cards.map((_, i) => (
          <div key={i} style={{
            flex: 1, height: 2.5, borderRadius: 2,
            background: `${p.ink}33`, overflow: 'hidden',
          }}>
            <div style={{
              width: `${i < idx ? 100 : i === idx ? progress * 100 : 0}%`,
              height: '100%', background: p.ink,
            }} />
          </div>
        ))}
      </div>

      {/* header: ep + close */}
      <div style={{
        position: 'absolute', top: 70, left: 16, right: 16, zIndex: 5,
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <div style={{
            width: 30, height: 30, borderRadius: '50%',
            background: p.accent, color: p.bg,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontFamily: '"Anton", sans-serif', fontSize: 16,
          }}>{ep.id}</div>
          <div>
            <div style={{
              fontFamily: '"Space Grotesk", system-ui', fontWeight: 700,
              fontSize: 12, letterSpacing: '0.08em', textTransform: 'uppercase',
            }}>Tattletales · {ep.ep}</div>
            <div style={{
              fontFamily: '"Space Grotesk", system-ui',
              fontSize: 11, opacity: 0.6, marginTop: 1,
            }}>{ep.kicker.toLowerCase()}</div>
          </div>
        </div>
        <button onClick={onClose} style={{
          all: 'unset', cursor: 'pointer', width: 30, height: 30,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
        }}>
          <svg width="22" height="22" viewBox="0 0 22 22"><path d="M5 5l12 12M17 5L5 17" stroke={p.ink} strokeWidth="2" strokeLinecap="round"/></svg>
        </button>
      </div>

      {/* tap zones */}
      <div onClick={prev} onMouseDown={() => setPaused(true)} onMouseUp={() => setPaused(false)}
        onTouchStart={() => setPaused(true)} onTouchEnd={() => setPaused(false)}
        style={{ position: 'absolute', top: 110, bottom: 90, left: 0, width: '35%', zIndex: 3, cursor: 'pointer' }} />
      <div onClick={next} onMouseDown={() => setPaused(true)} onMouseUp={() => setPaused(false)}
        onTouchStart={() => setPaused(true)} onTouchEnd={() => setPaused(false)}
        style={{ position: 'absolute', top: 110, bottom: 90, right: 0, width: '65%', zIndex: 3, cursor: 'pointer' }} />

      {/* card content */}
      <div style={{ position: 'absolute', inset: 0, padding: '120px 26px 110px', display: 'flex', flexDirection: 'column' }}>
        {card.kind === 'cover' && (
          <div style={{ display: 'flex', flexDirection: 'column', height: '100%', justifyContent: 'space-between' }}>
            <div style={{ marginTop: 8 }}>
              <TTTape color={p.tape}>{ep.kicker}</TTTape>
            </div>
            <div>
              <div style={{
                fontFamily: '"Anton", sans-serif', fontSize: 86, lineHeight: 0.85,
                textTransform: 'uppercase', textWrap: 'balance',
              }}>{ep.title}</div>
              <div style={{
                fontFamily: '"Instrument Serif", serif', fontStyle: 'italic',
                fontSize: 22, lineHeight: 1.25, marginTop: 18,
                opacity: 0.9, textWrap: 'pretty',
              }}>"{ep.logline}"</div>
            </div>
            <div style={{ alignSelf: 'flex-end' }}>
              <TTStamp color={p.accent} size={108} rot={14}>{ep.stamp}</TTStamp>
            </div>
          </div>
        )}

        {card.kind === 'redacted' && (
          <div style={{ display: 'flex', flexDirection: 'column', height: '100%', justifyContent: 'center', gap: 22 }}>
            <div style={{
              fontFamily: '"Space Grotesk", system-ui', fontWeight: 700,
              fontSize: 10, letterSpacing: '0.22em', textTransform: 'uppercase',
              opacity: 0.7,
            }}>Intercepted</div>
            <div style={{
              border: `1px solid ${p.ink}30`, borderRadius: 14, padding: 22,
              background: `${p.ink}06`,
              fontFamily: '"Instrument Serif", serif',
              fontSize: 26, lineHeight: 1.35, textWrap: 'pretty',
            }}>
              {card.lines.map((line, i) => (
                <div key={i} style={{ marginBottom: i === card.lines.length - 1 ? 0 : 6,
                  fontStyle: i === card.lines.length - 1 ? 'normal' : 'italic',
                  fontSize: i === card.lines.length - 1 ? 13 : 26,
                  opacity: i === card.lines.length - 1 ? 0.6 : 1,
                  fontFamily: i === card.lines.length - 1
                    ? '"Space Grotesk", system-ui'
                    : '"Instrument Serif", serif',
                  letterSpacing: i === card.lines.length - 1 ? '0.1em' : 'normal',
                  textTransform: i === card.lines.length - 1 ? 'uppercase' : 'none',
                }}
                dangerouslySetInnerHTML={{ __html: line.replace(/█+/g, m => `<span style="display:inline-block;height:0.8em;width:${m.length*0.55}em;background:${p.ink};border-radius:1px;vertical-align:-0.05em;margin:0 1px"></span>`) }} />
              ))}
            </div>
            <div style={{
              fontFamily: '"Space Grotesk", system-ui',
              fontSize: 11, letterSpacing: '0.1em', textTransform: 'uppercase',
              opacity: 0.55,
            }}>Source: anonymous · received 12:04 am</div>
          </div>
        )}

        {card.kind === 'tease' && (
          <div style={{ display: 'flex', flexDirection: 'column', height: '100%', justifyContent: 'space-between' }}>
            <div style={{
              fontFamily: '"Space Grotesk", system-ui', fontWeight: 700,
              fontSize: 11, letterSpacing: '0.22em', textTransform: 'uppercase',
              color: p.accent,
            }}>The Tease</div>
            <div style={{
              fontFamily: '"Instrument Serif", serif', fontStyle: 'italic',
              fontSize: 34, lineHeight: 1.15, textWrap: 'balance',
            }}>"{card.text}"</div>
            <button onClick={(e) => { e.stopPropagation(); onOpenDetail(ep.id); }} style={{
              all: 'unset', cursor: 'pointer', alignSelf: 'stretch', textAlign: 'center',
              padding: '14px 18px', borderRadius: 999,
              background: p.ink, color: p.bg,
              fontFamily: '"Space Grotesk", system-ui', fontWeight: 700,
              fontSize: 13, letterSpacing: '0.1em', textTransform: 'uppercase',
            }}>Open Episode →</button>
          </div>
        )}
      </div>
    </div>
  );
}

