function TeaFeed({ vibe, onOpenDetail }) {
  // Merge all takes into one chronological-ish feed
  const feed = React.useMemo(() => {
    const items = [];
    window.EPISODES.forEach(ep => {
      ep.takes.forEach(t => items.push({ ...t, ep }));
    });
    return items.sort((a, b) => a.mins - b.mins);
  }, []);

  return (
    <div style={{ padding: '14px 18px 110px', color: vibe.ink }}>
      <div style={{ padding: '8px 0 16px' }}>
        <div style={{
