      </div>

      {/* Chips: filter by ep */}
      <div style={{ display: 'flex', gap: 6, overflowX: 'auto', paddingBottom: 16, scrollbarWidth: 'none' }}>
        {[{ id: 'all', label: 'All', accent: vibe.accent }, ...window.EPISODES.map(e => ({ id: e.id, label: e.title, accent: e.palette.accent, palette: e.palette }))].map((c, i) => (
          <div key={c.id} style={{
            flexShrink: 0, padding: '7px 12px', borderRadius: 999,
            border: `1px solid ${vibe.rule}`,
            background: i === 0 ? vibe.ink : 'transparent',
            color: i === 0 ? vibe.page : vibe.ink,
            fontFamily: '"Space Grotesk", system-ui', fontWeight: 600,
