// ─────────────────────────────────────────────────────────────
// App root
// ─────────────────────────────────────────────────────────────
const TWEAK_DEFAULTS = /*EDITMODE-BEGIN*/{
  "vibe": "tabloid",
  "showStickers": true,
  "density": "regular"
}/*EDITMODE-END*/;

function App() {
  const [t, setTweak] = useTweaks(TWEAK_DEFAULTS);
  const vibe = window.VIBES[t.vibe] || window.VIBES.tabloid;

  const [tab, setTab] = React.useState('stories');
  const [overlay, setOverlay] = React.useState(null); // {kind:'story'|'detail', episodeId}
  const [watched, setWatched] = React.useState(() => new Set());

  const openStory = (id) => setOverlay({ kind: 'story', episodeId: id });
  const openDetail = (id) => setOverlay({ kind: 'detail', episodeId: id });
  const closeOverlay = () => setOverlay(null);
  const advanceStory = () => {
    const current = overlay?.episodeId ?? 1;
    setWatched(prev => new Set(prev).add(current));
    const idx = window.EPISODES.findIndex(e => e.id === current);
    const nextEp = window.EPISODES[idx + 1];
    if (nextEp) setOverlay({ kind: 'story', episodeId: nextEp.id });
    else setOverlay(null);
  };

  // CSS variables on the device for vibe
  const deviceStyle = {
    '--page': vibe.page, '--ink': vibe.ink, '--accent': vibe.accent, '--muted': vibe.muted,
    background: vibe.page,
  };

  return (
    <div style={{
      minHeight: '100vh', width: '100%', display: 'flex',
      alignItems: 'center', justifyContent: 'center', padding: 24,
      background: 'radial-gradient(ellipse at 30% 20%, #1a1414 0%, #0a0708 60%, #000 100%)',
      fontFamily: '"Space Grotesk", system-ui, sans-serif',
    }}>
      <IOSDevice width={402} height={874} dark={vibe.chrome === 'dark'}>
        <div style={{ ...deviceStyle, position: 'absolute', inset: 0, overflow: 'hidden' }}>
          {/* Tab content */}
          <div style={{ position: 'absolute', inset: 0, paddingTop: 44, overflow: 'auto' }}>
            {tab === 'stories' && (
              <HomeScreen vibe={vibe}
                onOpenStory={openStory} onOpenDetail={openDetail} watched={watched} />
            )}
            {tab === 'series' && (
              <>
                <MiniBrand vibe={vibe} />
                <SeriesGrid vibe={vibe} onOpenDetail={openDetail} />
              </>
            )}
            {tab === 'tea' && (
              <>
                <MiniBrand vibe={vibe} />
                <TeaFeed vibe={vibe} onOpenDetail={openDetail} />
              </>
            )}
            {tab === 'you' && (
              <>
                <MiniBrand vibe={vibe} />
                <YouScreen vibe={vibe} />
              </>
            )}
          </div>

          {/* Tab bar — hidden during story overlay */}
          {!overlay && <TabBar tab={tab} setTab={setTab} vibe={vibe} />}

          {/* Overlays */}
          {overlay?.kind === 'story' && (
            <StoryScreen episodeId={overlay.episodeId}
              onClose={closeOverlay}
              onOpenDetail={(id) => setOverlay({ kind: 'detail', episodeId: id })}
              onAdvanceEpisode={advanceStory} />
          )}
          {overlay?.kind === 'detail' && (
            <DetailScreen episodeId={overlay.episodeId}
              vibe={vibe}
              onClose={closeOverlay}
              onOpenStory={(id) => setOverlay({ kind: 'story', episodeId: id })} />
          )}
        </div>
      </IOSDevice>

      <TweaksPanel>
        <TweakSection label="Vibe" />
        <TweakRadio label="Palette" value={t.vibe}
          options={['tabloid','noir','editorial','y2k']}
          onChange={(v) => setTweak('vibe', v)} />
        <TweakSection label="Layout" />
        <TweakRadio label="Density" value={t.density}
          options={['compact','regular','comfy']}
          onChange={(v) => setTweak('density', v)} />
        <TweakToggle label="Show stickers" value={t.showStickers}
          onChange={(v) => setTweak('showStickers', v)} />
      </TweaksPanel>
    </div>
  );
}

ReactDOM.createRoot(document.getElementById('root')).render(<App />);
